@layer mergora.components {
  .mrg-message {
    display: grid;
    gap: var(--mrg-semantic-space-stack-sm);
    max-inline-size: min(100%, var(--mrg-semantic-size-content-prose));
    padding: var(--mrg-semantic-density-panel-padding);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-panel);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
    overflow-wrap: anywhere;
  }

  .mrg-message[data-message-role="assistant"] {
    border-block-start-color: var(--mrg-semantic-color-brand-action);
  }

  .mrg-message[data-message-role="user"] {
    margin-inline-start: auto;
    border-block-start-color: var(--mrg-semantic-color-brand-violet);
    background: var(--mrg-semantic-color-background-surface);
  }

  .mrg-message[data-message-role="system"],
  .mrg-message[data-message-role="tool"] {
    max-inline-size: 100%;
    border-style: dashed;
  }

  .mrg-message [data-slot="message-header"],
  .mrg-message [data-slot="message-role-context"],
  .mrg-message [data-slot="message-actions"] {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-inline-sm);
  }

  .mrg-message [data-slot="message-header"] time,
  .mrg-message [data-slot="message-metadata"] {
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-label);
  }

  .mrg-message [data-slot="message-role-context"] {
    margin: 0;
    padding-block: var(--mrg-semantic-space-inset-xs);
    border-block: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    color: var(--mrg-semantic-color-accent-foreground-on-subtle);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
  }

  .mrg-message [data-slot="message-content"] {
    line-height: var(--mrg-semantic-font-line-height-body);
    white-space: pre-wrap;
  }

  .mrg-message :is(a, button):focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }

  @media (max-width: 32rem) {
    .mrg-message {
      max-inline-size: 100%;
      padding: var(--mrg-semantic-space-inset-md);
    }
  }

  @media (forced-colors: active) {
    .mrg-message,
    .mrg-message[data-message-role="user"] {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
    }
    .mrg-message :is(a, button):focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }
  }
}

import "./message.css";

import { forwardRef, type HTMLAttributes, type ReactNode } from "react";

export type MessageRole = "assistant" | "system" | "tool" | "user";
export type MessageDeliveryState = "complete" | "error" | "pending" | "streaming";

export interface MessageProps extends Omit<HTMLAttributes<HTMLElement>, "children"> {
  /** Optional consumer actions rendered in the message footer. */
  readonly actions?: ReactNode;
  /** Optional visible author identity rendered alongside the timestamp. */
  readonly author?: ReactNode;
  /** Primary message content rendered in a dedicated content region. */
  readonly children: ReactNode;
  /** Delivery lifecycle reflected by stable state metadata for styling and context. */
  readonly deliveryState?: MessageDeliveryState;
  /** Optional supporting metadata rendered after the primary message content. */
  readonly metadata?: ReactNode;
  /** Semantic conversation origin used for role context and family styling. */
  readonly role: MessageRole;
  /** Localized role-name overrides merged with defaults for omitted roles. */
  readonly roleLabels?: Partial<Record<MessageRole, string>>;
  /** Adds visible role and delivery context; false removes that extra explanatory UI. */
  readonly showRoleContext?: boolean;
  /** Valid date rendered with a machine-readable ISO `dateTime` and localized visible text. */
  readonly timestamp?: Date | string;
}

const DEFAULT_ROLE_LABELS: Readonly<Record<MessageRole, string>> = {
  assistant: "Assistant",
  system: "System",
  tool: "Tool",
  user: "You",
};

function timestampValue(value: Date | string): {
  readonly dateTime: string;
  readonly text: string;
} {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.valueOf())) {
    throw new RangeError("Mergora Message timestamp must be a valid date.");
  }
  return { dateTime: date.toISOString(), text: date.toLocaleString() };
}

export const Message = forwardRef<HTMLElement, MessageProps>(function Message(
  {
    actions,
    author,
    children,
    className,
    deliveryState = "complete",
    metadata,
    role,
    roleLabels,
    showRoleContext = false,
    timestamp,
    ...props
  },
  ref,
) {
  const roleLabel = roleLabels?.[role] ?? DEFAULT_ROLE_LABELS[role];
  const time = timestamp === undefined ? null : timestampValue(timestamp);

  return (
    <article
      {...props}
      className={className === undefined ? "mrg-message" : `mrg-message ${className}`}
      data-delivery-state={deliveryState}
      data-message-role={role}
      data-slot="message"
      ref={ref}
    >
      {author !== undefined || time !== null ? (
        <header data-slot="message-header">
          {author === undefined ? null : <strong>{author}</strong>}
          {time === null ? null : <time dateTime={time.dateTime}>{time.text}</time>}
        </header>
      ) : null}
      {showRoleContext ? (
        <p data-slot="message-role-context">
          <span>{roleLabel}</span>
          <span>{deliveryState}</span>
        </p>
      ) : null}
      <div data-slot="message-content">{children}</div>
      {metadata === undefined ? null : <div data-slot="message-metadata">{metadata}</div>}
      {actions === undefined ? null : <footer data-slot="message-actions">{actions}</footer>}
    </article>
  );
});

Message.displayName = "Message";
